-- Remove old ADK seed templates from 006 (we replace with richer versions)
DELETE FROM flow_templates WHERE framework = 'google-adk';

INSERT INTO flow_templates (`template_id`, `name`, `description`, `framework`, `category`, `pattern`, `difficulty`, `tags`, `source_url`, `source_author`, `is_official`, `is_published`, `flow_data`) VALUES

-- Template 1: Production-Ready ADK Agent
('adk-production-agent', 'Production-Ready ADK Agent (Full Features)', 'Demonstrates key ADK features: LlmAgent with callbacks (guardrails), FunctionTool, Google Search, session state, output_key, and GenerateContentConfig.', 'google-adk', 'single-agent', NULL, 'intermediate', '["production", "callbacks", "guardrails", "tools", "session", "state", "adk"]', 'https://google.github.io/adk-docs/agents/llm-agents/', 'Google ADK Docs', TRUE, TRUE, '{"nodes":[{"id":"input_1","type":"adk-input","position":{"x":60,"y":220},"data":{"label":"User Request"}},{"id":"agent_1","type":"adk-llm-agent","position":{"x":400,"y":180},"data":{"label":"Production Agent","name":"production_agent","model":"gemini-2.0-flash","modelProvider":"gemini","instruction":"You are a production-grade AI assistant. Use available tools to research and provide accurate answers.","description":"Main production agent with guardrails","outputKey":"last_response","beforeModelCallback":true,"afterModelCallback":true,"temperature":0.7,"maxOutputTokens":4096,"topP":0.95,"sessionType":"in-memory"}},{"id":"tool_search","type":"adk-builtin-tool","position":{"x":380,"y":40},"data":{"label":"Google Search","toolType":"google_search"}},{"id":"tool_custom","type":"adk-function-tool","position":{"x":600,"y":40},"data":{"label":"Validate Data","functionName":"validate_data","description":"Validate and sanitize user-provided data"}},{"id":"output_1","type":"adk-output","position":{"x":720,"y":220},"data":{"label":"Verified Response"}}],"edges":[{"id":"e1","source":"input_1","target":"agent_1","targetHandle":"input","animated":true},{"id":"e2","source":"tool_search","target":"agent_1","targetHandle":"tools","animated":true},{"id":"e3","source":"tool_custom","target":"agent_1","targetHandle":"tools","animated":true},{"id":"e4","source":"agent_1","sourceHandle":"output","target":"output_1","animated":true}]}'),

-- Template 2: Sequential Pipeline
('adk-sequential-pipeline', 'Research-Write-Review Pipeline (Sequential)', 'Three-stage sequential pipeline: Researcher gathers information, Writer produces content, Reviewer polishes it. Each agent passes results via output_key.', 'google-adk', 'custom', 'Sequential', 'beginner', '["sequential", "pipeline", "research", "writing", "review", "adk"]', 'https://google.github.io/adk-docs/agents/workflow-agents/sequential-agent/', 'Google ADK Docs', TRUE, TRUE, '{"nodes":[{"id":"input_1","type":"adk-input","position":{"x":60,"y":220},"data":{"label":"Topic"}},{"id":"researcher","type":"adk-llm-agent","position":{"x":280,"y":80},"data":{"label":"Researcher","name":"researcher","model":"gemini-2.0-flash","instruction":"Research the given topic thoroughly. Find key facts and statistics.","outputKey":"research_notes"}},{"id":"writer","type":"adk-llm-agent","position":{"x":280,"y":220},"data":{"label":"Writer","name":"writer","model":"gemini-2.0-flash","instruction":"Using the research notes, write a well-structured article.","outputKey":"draft"}},{"id":"reviewer","type":"adk-llm-agent","position":{"x":280,"y":360},"data":{"label":"Reviewer","name":"reviewer","model":"gemini-2.0-flash","instruction":"Review the draft for clarity and accuracy. Provide the final polished version.","outputKey":"final_article"}},{"id":"pipeline","type":"adk-sequential","position":{"x":560,"y":220},"data":{"label":"Content Pipeline","name":"content_pipeline","description":"Research then Write then Review"}},{"id":"output_1","type":"adk-output","position":{"x":800,"y":220},"data":{"label":"Published Article"}}],"edges":[{"id":"e1","source":"input_1","target":"pipeline","animated":true},{"id":"e2","source":"researcher","target":"pipeline","targetHandle":"sub-agents","animated":true},{"id":"e3","source":"writer","target":"pipeline","targetHandle":"sub-agents","animated":true},{"id":"e4","source":"reviewer","target":"pipeline","targetHandle":"sub-agents","animated":true},{"id":"e5","source":"pipeline","target":"output_1","animated":true}]}'),

-- Template 3: Parallel Multi-Source Gathering
('adk-parallel-gatherer', 'Multi-Source Intelligence Gatherer (Parallel)', 'Parallel agent dispatches to 4 specialized sources simultaneously. Results aggregated by a synthesizer.', 'google-adk', 'custom', 'Parallel', 'intermediate', '["parallel", "multi-source", "intelligence", "concurrent", "adk"]', 'https://google.github.io/adk-docs/agents/workflow-agents/parallel-agent/', 'Google ADK Docs', TRUE, TRUE, '{"nodes":[{"id":"input_1","type":"adk-input","position":{"x":60,"y":250},"data":{"label":"Research Topic"}},{"id":"news","type":"adk-llm-agent","position":{"x":280,"y":60},"data":{"label":"News Agent","name":"news_agent","model":"gemini-2.0-flash","instruction":"Search for and summarize the latest news on the topic.","outputKey":"news_results"}},{"id":"academic","type":"adk-llm-agent","position":{"x":280,"y":180},"data":{"label":"Academic Agent","name":"academic_agent","model":"gemini-2.0-flash","instruction":"Find relevant academic papers and research.","outputKey":"academic_results"}},{"id":"financial","type":"adk-llm-agent","position":{"x":280,"y":300},"data":{"label":"Financial Agent","name":"financial_agent","model":"gemini-2.0-flash","instruction":"Analyze financial implications and market data.","outputKey":"financial_results"}},{"id":"social","type":"adk-llm-agent","position":{"x":280,"y":420},"data":{"label":"Social Agent","name":"social_agent","model":"gemini-2.0-flash","instruction":"Analyze public sentiment and social discussions.","outputKey":"social_results"}},{"id":"gatherer","type":"adk-parallel","position":{"x":560,"y":250},"data":{"label":"Data Gatherer","name":"intelligence_gatherer","description":"All 4 sources run concurrently"}},{"id":"output_1","type":"adk-output","position":{"x":800,"y":250},"data":{"label":"Intelligence Briefing"}}],"edges":[{"id":"e1","source":"input_1","target":"gatherer","animated":true},{"id":"e2","source":"news","target":"gatherer","targetHandle":"sub-agents","animated":true},{"id":"e3","source":"academic","target":"gatherer","targetHandle":"sub-agents","animated":true},{"id":"e4","source":"financial","target":"gatherer","targetHandle":"sub-agents","animated":true},{"id":"e5","source":"social","target":"gatherer","targetHandle":"sub-agents","animated":true},{"id":"e6","source":"gatherer","target":"output_1","animated":true}]}'),

-- Template 4: Writer-Reviewer Loop
('adk-feedback-loop', 'Writer-Reviewer Feedback Loop (Loop Agent)', 'Iterative refinement: Writer drafts content, Critic evaluates. Loop continues until Critic escalates (approves). Max 5 iterations.', 'google-adk', 'custom', 'Loop', 'intermediate', '["loop", "feedback", "iterative", "refinement", "writer", "reviewer", "adk"]', 'https://google.github.io/adk-docs/agents/workflow-agents/loop-agent/', 'Google ADK Docs', TRUE, TRUE, '{"nodes":[{"id":"input_1","type":"adk-input","position":{"x":60,"y":200},"data":{"label":"Writing Brief"}},{"id":"writer","type":"adk-llm-agent","position":{"x":280,"y":120},"data":{"label":"Content Writer","name":"writer","model":"gemini-2.0-flash","instruction":"Write or revise content based on the brief and any feedback. Aim for clarity and engagement.","outputKey":"current_draft"}},{"id":"critic","type":"adk-llm-agent","position":{"x":280,"y":300},"data":{"label":"Quality Critic","name":"critic","model":"gemini-2.5-pro","instruction":"Review the current draft. Score 1-10. If score >= 8, escalate to end the loop. Otherwise provide specific feedback.","outputKey":"feedback"}},{"id":"loop","type":"adk-loop","position":{"x":540,"y":200},"data":{"label":"Refinement Loop","name":"refinement_loop","description":"Write then Critique until approved","maxIterations":5}},{"id":"output_1","type":"adk-output","position":{"x":780,"y":200},"data":{"label":"Approved Content"}}],"edges":[{"id":"e1","source":"input_1","target":"loop","animated":true},{"id":"e2","source":"writer","target":"loop","targetHandle":"sub-agents","animated":true},{"id":"e3","source":"critic","target":"loop","targetHandle":"sub-agents","animated":true},{"id":"e4","source":"loop","target":"output_1","animated":true}]}'),

-- Template 5: MCP-Powered Agent
('adk-mcp-agent', 'MCP-Powered Research Agent (External Tools)', 'Agent connected to MCP servers: filesystem (stdio) and web API (SSE). Plus built-in Google Search and a custom FunctionTool.', 'google-adk', 'single-agent', 'Single + MCP', 'intermediate', '["mcp", "tools", "filesystem", "api", "stdio", "sse", "adk"]', 'https://google.github.io/adk-docs/tools-custom/mcp-tools/', 'Google ADK Docs', TRUE, TRUE, '{"nodes":[{"id":"input_1","type":"adk-input","position":{"x":60,"y":220},"data":{"label":"Research Query"}},{"id":"tool_search","type":"adk-builtin-tool","position":{"x":300,"y":50},"data":{"label":"Google Search","toolType":"google_search"}},{"id":"mcp_fs","type":"adk-mcp-tool","position":{"x":300,"y":390},"data":{"label":"Filesystem (stdio)","serverName":"filesystem","transport":"stdio","command":"npx -y @modelcontextprotocol/server-filesystem /tmp/research"}},{"id":"mcp_api","type":"adk-mcp-tool","position":{"x":540,"y":390},"data":{"label":"API Server (SSE)","serverName":"api_server","transport":"sse","url":"http://localhost:3001/sse"}},{"id":"agent","type":"adk-llm-agent","position":{"x":420,"y":220},"data":{"label":"Research Agent","name":"research_agent","model":"gemini-2.0-flash","instruction":"You are a research agent with web search, file system, and API access. Search, save findings, and cite sources.","outputKey":"research_output"}},{"id":"output_1","type":"adk-output","position":{"x":720,"y":220},"data":{"label":"Research Report"}}],"edges":[{"id":"e1","source":"input_1","target":"agent","targetHandle":"input","animated":true},{"id":"e2","source":"tool_search","target":"agent","targetHandle":"tools","animated":true},{"id":"e3","source":"mcp_fs","target":"agent","targetHandle":"tools","animated":true},{"id":"e4","source":"mcp_api","target":"agent","targetHandle":"tools","animated":true},{"id":"e5","source":"agent","sourceHandle":"output","target":"output_1","animated":true}]}'),

-- Template 6: Customer Support Orchestrator (Agent Routing)
('adk-orchestrator-routing', 'Customer Support Orchestrator (Agent Routing)', 'LlmAgent routes requests to specialized sub-agents. The ADK equivalent of Agents-as-Tools pattern.', 'google-adk', 'custom', 'Routing', 'intermediate', '["orchestrator", "routing", "sub-agents", "customer-support", "adk"]', 'https://google.github.io/adk-docs/agents/llm-agents/', 'Google ADK Docs', TRUE, TRUE, '{"nodes":[{"id":"input_1","type":"adk-input","position":{"x":60,"y":220},"data":{"label":"Customer Query"}},{"id":"router","type":"adk-llm-agent","position":{"x":360,"y":200},"data":{"label":"Support Router","name":"support_router","model":"gemini-2.0-flash","instruction":"Route queries to the appropriate specialist: tech_support for technical issues, billing_support for billing, general_support for everything else.","description":"Routes to specialist"}},{"id":"tech","type":"adk-llm-agent","position":{"x":700,"y":80},"data":{"label":"Tech Support","name":"tech_support","model":"gemini-2.0-flash","instruction":"Help with software bugs, configuration, API problems. Provide step-by-step solutions.","description":"Technical issues"}},{"id":"billing","type":"adk-llm-agent","position":{"x":700,"y":220},"data":{"label":"Billing Support","name":"billing_support","model":"gemini-2.0-flash","instruction":"Help with invoices, payments, subscriptions, refunds, and pricing.","description":"Billing questions"}},{"id":"general","type":"adk-llm-agent","position":{"x":700,"y":360},"data":{"label":"General Support","name":"general_support","model":"gemini-2.0-flash","instruction":"Handle general inquiries: account info, feature requests, feedback.","description":"General inquiries"}},{"id":"output_1","type":"adk-output","position":{"x":360,"y":420},"data":{"label":"Support Response"}}],"edges":[{"id":"e1","source":"input_1","target":"router","targetHandle":"input","animated":true},{"id":"e2","source":"router","sourceHandle":"sub-agents","target":"tech","animated":true},{"id":"e3","source":"router","sourceHandle":"sub-agents","target":"billing","animated":true},{"id":"e4","source":"router","sourceHandle":"sub-agents","target":"general","animated":true},{"id":"e5","source":"router","sourceHandle":"output","target":"output_1","animated":true}]}'),

-- Template 7: Nested Workflow (Sequential + Parallel)
('adk-nested-workflow', 'Nested Workflow (Sequential + Parallel)', 'Complex workflow combining Sequential and Parallel agents. Outer pipeline with inner parallel development stage.', 'google-adk', 'custom', 'Nested', 'advanced', '["nested", "sequential", "parallel", "composable", "workflow", "adk"]', 'https://google.github.io/adk-docs/agents/workflow-agents/', 'Google ADK Docs', TRUE, TRUE, '{"nodes":[{"id":"input_1","type":"adk-input","position":{"x":60,"y":250},"data":{"label":"Project Brief"}},{"id":"planner","type":"adk-llm-agent","position":{"x":260,"y":250},"data":{"label":"Planner","name":"planner","model":"gemini-2.0-flash","instruction":"Break down the project brief into tasks. Identify parallel vs sequential work.","outputKey":"project_plan"}},{"id":"dev_frontend","type":"adk-llm-agent","position":{"x":500,"y":120},"data":{"label":"Frontend Dev","name":"frontend_dev","model":"gemini-2.0-flash","instruction":"Implement frontend components from the plan.","outputKey":"frontend_code"}},{"id":"dev_backend","type":"adk-llm-agent","position":{"x":500,"y":250},"data":{"label":"Backend Dev","name":"backend_dev","model":"gemini-2.0-flash","instruction":"Implement backend API from the plan.","outputKey":"backend_code"}},{"id":"dev_tests","type":"adk-llm-agent","position":{"x":500,"y":380},"data":{"label":"Test Writer","name":"test_writer","model":"gemini-2.0-flash","instruction":"Write tests for frontend and backend.","outputKey":"test_code"}},{"id":"parallel_dev","type":"adk-parallel","position":{"x":740,"y":250},"data":{"label":"Parallel Dev","name":"parallel_dev","description":"Frontend + Backend + Tests simultaneously"}},{"id":"integrator","type":"adk-llm-agent","position":{"x":960,"y":250},"data":{"label":"Integrator","name":"integrator","model":"gemini-2.5-pro","instruction":"Review all code, verify integration, produce final report.","outputKey":"integration_report"}},{"id":"pipeline","type":"adk-sequential","position":{"x":1180,"y":250},"data":{"label":"Full Pipeline","name":"project_pipeline","description":"Plan then Develop then Integrate"}},{"id":"output_1","type":"adk-output","position":{"x":1400,"y":250},"data":{"label":"Delivery"}}],"edges":[{"id":"e1","source":"input_1","target":"pipeline","animated":true},{"id":"e2","source":"planner","target":"pipeline","targetHandle":"sub-agents","animated":true},{"id":"e3","source":"dev_frontend","target":"parallel_dev","targetHandle":"sub-agents","animated":true},{"id":"e4","source":"dev_backend","target":"parallel_dev","targetHandle":"sub-agents","animated":true},{"id":"e5","source":"dev_tests","target":"parallel_dev","targetHandle":"sub-agents","animated":true},{"id":"e6","source":"parallel_dev","target":"pipeline","targetHandle":"sub-agents","animated":true},{"id":"e7","source":"integrator","target":"pipeline","targetHandle":"sub-agents","animated":true},{"id":"e8","source":"pipeline","target":"output_1","animated":true}]}'),

-- Template 8: Callbacks & Guardrails
('adk-callbacks-guardrails', 'Callbacks & Guardrails (Safety Pattern)', 'All 6 ADK callbacks as guardrails: before_agent, after_agent, before_model (content filter), after_model (sanitize), before_tool (policy), after_tool (audit).', 'google-adk', 'single-agent', NULL, 'advanced', '["callbacks", "guardrails", "safety", "content-filter", "audit", "policy", "adk"]', 'https://google.github.io/adk-docs/callbacks/', 'Google ADK Docs', TRUE, TRUE, '{"nodes":[{"id":"input_1","type":"adk-input","position":{"x":60,"y":200},"data":{"label":"User Input"}},{"id":"agent_1","type":"adk-llm-agent","position":{"x":420,"y":180},"data":{"label":"Guarded Agent","name":"guarded_agent","model":"gemini-2.0-flash","modelProvider":"gemini","instruction":"You are a helpful assistant that follows strict safety guidelines. Never reveal personal data or generate harmful content.","description":"Agent with full callback guardrails","outputKey":"response","beforeAgentCallback":true,"afterAgentCallback":true,"beforeModelCallback":true,"afterModelCallback":true,"beforeToolCallback":true,"afterToolCallback":true,"temperature":0.7,"maxOutputTokens":2048}},{"id":"tool_search","type":"adk-builtin-tool","position":{"x":400,"y":40},"data":{"label":"Google Search","toolType":"google_search"}},{"id":"tool_pii","type":"adk-function-tool","position":{"x":600,"y":40},"data":{"label":"PII Detector","functionName":"detect_pii","description":"Scans text for personally identifiable information"}},{"id":"output_1","type":"adk-output","position":{"x":720,"y":200},"data":{"label":"Safe Response"}}],"edges":[{"id":"e1","source":"input_1","target":"agent_1","targetHandle":"input","animated":true},{"id":"e2","source":"tool_search","target":"agent_1","targetHandle":"tools","animated":true},{"id":"e3","source":"tool_pii","target":"agent_1","targetHandle":"tools","animated":true},{"id":"e4","source":"agent_1","sourceHandle":"output","target":"output_1","animated":true}]}');
